text = path.read_text(encoding="utf-8")

# Find all segments inside double quotes "
segments = []
start = None
for i, ch in enumerate(text):
    if ch == '"':
        if start is None:
            start = i+1  # inside
        else:
            end = i
            segments.append((start, end, text[start:end]))
            start = None
# Print segments lengths and content
print(len(segments))
for s in segments:
    t = s[2]
    if "إِنَّ" in t or "قال" in t or "عن النبي" in t:
        print("SEGMENT:", t[:120], "... full len", len(t))
